perspectives.style:
@view "Rechercher" {
 @settings {
 focus: prompt;
 }
}

@controls {
  top-right {
    zoom-toolbar {}

    focus-toolbar {}
  }

  top-left {
    search {
      label: "Retrouver un élément : ";
      font-family: Marianne light;
      font-size: 12;
      opacity: 0.7;
    }
  }

  bottom-right {
    label {
      value: "©Cerema-2025";
      font-size: 13;
      font-weight: 300;
      color: #26216a;
      font-family: Marianne;
      margin: 10;
    }
  }

  bottom-left {}
}

@settings {
  template: clone;
  element-text-align: bottom;
  element-size: 50;
  opposite-label: "";
  font-cutoff: 5;
  font-family: Marianne;
  font-size: 15;
  ignore: ["label"="focus  gouvernance"], #elem-V0TX4tet, #elem-rMWxfH0X;
  culling: true;
  theme: light;
  quality: best;
  connection-color: ccc;
  showcase: ["element type"="A - Facteur climatique : paramètre"], ["connection type"="Same"];
}

/* Changement de paramètres climatique */
element["element type"="A - Facteur climatique : paramètre"] {
  color: #c3161b;
  shape: pentagon;
}

element {
  scale: scale("niveau détails", 1, 1);
}

element["niveau détail"="2"] {
  color: transparent;
}

/* Aléas induits */
element["element type"="B - Facteur climatique : Aléas et risques naturel"] {
  color: #ef7757;
  shape: hexagon;
}

/* Ressources du territoire */
element["element type"="C - Facteur non climatique : Ressource territoire"] {
  color: #448d60;
  shape: octagon;
}

/* Population et usages */
element["element type"="D - Facteur non climatique : Usages et population"] {
  color: #26216a;
  shape: circle;
  font-color: #26216a;
}

element["aire attraction"="oui"]["degree">"3"], element["degree"="3"] {
  shadow-color: inherit;
  shadow-opacity: 0.09;
  shadow-size: 2.9;
}

element["aire attraction"="oui"]["degree"<"3"] {
  shadow-color: inherit;
  shadow-opacity: 0.13;
  shadow-size: 2.3;
}

element["aire attraction"="oui"]["degree">"4"] {
  shadow-color: inherit;
  shadow-opacity: 0.13;
  shadow-size: 3.4;
}

connection["aire attraction"="Oui"] {
  color: #ffffff;
}

* {
  profile: true;
}

element["label"="Retour Chaine principale"] {
  border-width: 0;
  font-weight: 700;
  label-offset: 50;
}

element["tags"="titre"] {
  font-weight: 300;
}

element["tags"="Gouvernance"] {
  border-color: #f7d05c;
  border-width: 9;
}

* {
  font-family: 'Marianne', sans-serif;
}

connection["direction"="mutual"]["mutual"="B-C"] {
  color: gradient(#36a155, #fd7234);
}

connection["direction"="mutual"]["mutual"="A-B"] {
  color: gradient(#fd7234, #d31114);
}

connection["direction"="mutual"]["mutual"="C-D"] {
  color: gradient(#26216a, #36a155);
}

connection["direction"="mutual"]["mutual"="B-D"] {
  color: gradient(#26216a, #fd7234);
}

@view "Rechercher" {
 @settings {
 focus: prompt;
 }
}

@controls {
  top-right {
    view-toggle {
      options: Rechercher;
      label: "Je crée ma chaine d'impact";
      font-family: Marianne;
      text-transform: uppercase;
      font-weight: 0;
      font-style: italic;
      font-size: 11;
      opacity: 0.7;
      as: buttons;
    }

    zoom-toolbar {}

    focus-toolbar {}
  }

  top-left {
    search {
      label: "Retrouver un élément : ";
      font-family: Marianne light;
      font-size: 12;
      opacity: 0.7;
    }

    filter {
      target: connection;
      by: "tags";
      except: Titre, Stock, Gouvernance, Flux;
      only: 🏭Activité industrielle et commerciale, ⚓Activité portuaire, 🖥️Activité de service, 🏛️Activités et patrimoine culturel, 🌽Agriculture - Culture, 🐄Agriculture - Elevage, 🏠Bâtiments, 💧Eau, ⚡Energie, 🚗Mobilité, 🏞️Paysage et aménagement, 🐟Pêche et aquaculture, 🌐Réseaux, 🩺Santé, 🚨Sécurité, 🌳Sylviculture, 📷Tourisme;
      as: dropdown;
      mode: out 1;
      default: show-all;
      label: "Par thématiques";
      font-family: Marianne;
      margin: 6;
      back-ground: 1;
      font-size: 11;
      multiple: true;
      text-align: left;
      width: 100;
      placeholder: "Choisir une thématique";
    }

    filter {
      target: connection;
      by: "Aléas";
      as: dropdown;
      mode: strict;
      default: show-all;
      label: "Par aléas";
      font-family: Marianne;
      margin: 6;
      back-ground: 1;
      font-size: 11;
      multiple: true;
      text-align: left;
      connect: true;
      show-connected: true;
      width: 100;
      height: 50;
      placeholder: "Choisir un aléa";
    }

    filter {
      target: element,connection;
      by: "typologie de territoire";
      as: button;
      label: "------------------";
      multiple: true;
      default: select-all;
      font-family: Marianne light;
      font-size: 10;
      opacity: 0.8;
      text-align: center;
      width: 60;
    }
  }

  bottom-left {
    legend {
      title: "  ";
      height: 95;
      margin: 5;
      width: 10;
      opacity: 0.5;
    }
  }

  bottom-right {
    label {
      value: "©Cerema-2025";
      font-size: 18;
      font-weight: 300;
      color: #26216a;
      font-family: Marianne;
      margin: 10;
    }
  }
}

