      opacity: 0.7;
    }
  }

  bottom-right {
    label {
      value: "©Cerema-2025";
      font-size: 11;
      font-weight: 300;
      color: #26216a;
      font-family: Marianne;
      margin: 10;
    }
  }
}

@settings {
  template: clone;
  element-text-align: bottom;
  element-size: 50;
  opposite-label: "";
  font-cutoff: 5;
  font-family: Marianne;
  font-size: 15;
  ignore: ["label"="focus  gouvernance"], #elem-V0TX4tet, #elem-rMWxfH0X;
  culling: true;
  theme: light;
  quality: best;
  connection-color: ccc;
  showcase: ["tags"="🩺Santé"] !strict;
}

/* Changement de paramètres climatique */
element["element type"="A - Facteur climatique : paramètre"] {
  color: #c3161b;
  shape: pentagon;
}

element {
  scale: scale("niveau détails", 1, 1);
}

element["niveau détail"="2"] {
  color: transparent;
}

/* Aléas induits */
element["element type"="B - Facteur climatique : Aléas et risques naturel"] {
  color: #ef7757;
  shape: hexagon;
}

/* Ressources du territoire */
element["element type"="C - Facteur non climatique : Ressource territoire"] {
  color: #448d60;
  shape: octagon;
}

/* Population et usages */
element["element type"="D - Facteur non climatique : Usages et population"] {
  color: #26216a;
  shape: circle;
  font-color: #26216a;
}

element["aire attraction"="oui"]["degree">"3"], element["degree"="3"] {
  shadow-color: inherit;
  shadow-opacity: 0.09;
  shadow-size: 2.9;
}

element["aire attraction"="oui"]["degree"<"3"] {
  shadow-color: inherit;
  shadow-opacity: 0.13;
  shadow-size: 2.3;
}

element["aire attraction"="oui"]["degree">"4"] {
  shadow-color: inherit;
  shadow-opacity: 0.13;
  shadow-size: 3.4;
}

connection["aire attraction"="Oui"] {
  color: #ffffff;
}

element {
  popover: "#### {{image}}  ---  {{description}}";
  popover-width: 300;
}

connection {
  label-visibility: hidden;
  popover: "{{description}}";
  popover-width: 500;
}

* {
  profile: true;
}

element["label"="Retour Chaine principale"] {
  border-width: 0;
  font-weight: 700;
  label-offset: 50;
}

element["tags"="titre"] {
  font-weight: 300;
}

element["tags"="Gouvernance"] {
  border-color: #f7d05c;
  border-width: 9;
}

* {
  font-family: 'Marianne', sans-serif;
}

connection["direction"="mutual"]["mutual"="B-C"] {
  color: gradient(#36a155, #fd7234);
}

connection["direction"="mutual"]["mutual"="A-B"] {
  color: gradient(#fd7234, #d31114);
}

connection["direction"="mutual"]["mutual"="C-D"] {
  color: gradient(#26216a, #36a155);
}

connection["direction"="mutual"]["mutual"="B-D"] {
  color: gradient(#26216a, #fd7234);
}
